PRAGMA foreign_keys = OFF;
BEGIN TRANSACTION;

CREATE TABLE "audit_logs" (
    "id" INTEGER PRIMARY KEY AUTOINCREMENT,
    "user_id" INTEGER DEFAULT NULL,
    "action" TEXT NOT NULL,
    "target_type" TEXT NOT NULL,
    "target_id" INTEGER DEFAULT NULL,
    "target_name" TEXT DEFAULT NULL,
    "description" TEXT DEFAULT NULL,
    "meta" TEXT DEFAULT NULL,
    "ip_address" TEXT DEFAULT NULL,
    "user_agent" TEXT DEFAULT NULL,
    "created_at" TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY ("user_id") REFERENCES "users" ("id") ON DELETE SET NULL
);

CREATE TABLE "bundle_ads" (
    "id" INTEGER PRIMARY KEY AUTOINCREMENT,
    "bundle_type" TEXT NOT NULL,
    "image_path" TEXT DEFAULT NULL,
    "image_url" TEXT DEFAULT NULL,
    "link_url" TEXT DEFAULT NULL,
    "sort_order" INTEGER NOT NULL DEFAULT 1,
    "is_active" INTEGER NOT NULL DEFAULT 1,
    "created_at" TEXT DEFAULT NULL,
    "updated_at" TEXT DEFAULT NULL
);

CREATE TABLE "cache" (
    "key" TEXT PRIMARY KEY,
    "value" TEXT NOT NULL,
    "expiration" INTEGER NOT NULL
);

CREATE TABLE "cache_locks" (
    "key" TEXT PRIMARY KEY,
    "owner" TEXT NOT NULL,
    "expiration" INTEGER NOT NULL
);

CREATE TABLE "carousel_slides" (
    "id" INTEGER PRIMARY KEY AUTOINCREMENT,
    "title" TEXT NOT NULL,
    "subtitle" TEXT DEFAULT NULL,
    "label" TEXT DEFAULT NULL,
    "image_path" TEXT DEFAULT NULL,
    "image_url" TEXT DEFAULT NULL,
    "sort_order" INTEGER NOT NULL DEFAULT 1,
    "is_active" INTEGER NOT NULL DEFAULT 1,
    "created_at" TEXT DEFAULT NULL,
    "updated_at" TEXT DEFAULT NULL
);

CREATE TABLE "categories" (
    "id" INTEGER PRIMARY KEY AUTOINCREMENT,
    "name" TEXT NOT NULL,
    "parent_id" INTEGER DEFAULT NULL,
    "created_at" TEXT DEFAULT NULL,
    "updated_at" TEXT DEFAULT NULL,
    FOREIGN KEY ("parent_id") REFERENCES "categories" ("id") ON DELETE CASCADE
);

CREATE TABLE "expenses" (
    "id" INTEGER PRIMARY KEY AUTOINCREMENT,
    "created_by" INTEGER DEFAULT NULL,
    "spent_at" TEXT NOT NULL,
    "title" TEXT NOT NULL,
    "category" TEXT DEFAULT NULL,
    "amount" NUMERIC NOT NULL,
    "notes" TEXT DEFAULT NULL,
    "created_at" TEXT DEFAULT NULL,
    "updated_at" TEXT DEFAULT NULL,
    FOREIGN KEY ("created_by") REFERENCES "users" ("id") ON DELETE SET NULL
);

CREATE TABLE "failed_jobs" (
    "id" INTEGER PRIMARY KEY AUTOINCREMENT,
    "uuid" TEXT NOT NULL,
    "connection" TEXT NOT NULL,
    "queue" TEXT NOT NULL,
    "payload" TEXT NOT NULL,
    "exception" TEXT NOT NULL,
    "failed_at" TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE "featured_brands" (
    "id" INTEGER PRIMARY KEY AUTOINCREMENT,
    "name" TEXT NOT NULL,
    "logo_path" TEXT DEFAULT NULL,
    "logo_url" TEXT DEFAULT NULL,
    "sort_order" INTEGER NOT NULL DEFAULT 1,
    "is_active" INTEGER NOT NULL DEFAULT 1,
    "created_at" TEXT DEFAULT NULL,
    "updated_at" TEXT DEFAULT NULL
);

CREATE TABLE "featured_builds" (
    "id" INTEGER PRIMARY KEY AUTOINCREMENT,
    "title" TEXT DEFAULT NULL,
    "image_path" TEXT DEFAULT NULL,
    "image_url" TEXT DEFAULT NULL,
    "gallery_images" TEXT DEFAULT NULL,
    "sort_order" INTEGER NOT NULL DEFAULT 1,
    "is_active" INTEGER NOT NULL DEFAULT 1,
    "created_at" TEXT DEFAULT NULL,
    "updated_at" TEXT DEFAULT NULL
);

CREATE TABLE "job_batches" (
    "id" TEXT PRIMARY KEY,
    "name" TEXT NOT NULL,
    "total_jobs" INTEGER NOT NULL,
    "pending_jobs" INTEGER NOT NULL,
    "failed_jobs" INTEGER NOT NULL,
    "failed_job_ids" TEXT NOT NULL,
    "options" TEXT DEFAULT NULL,
    "cancelled_at" INTEGER DEFAULT NULL,
    "created_at" INTEGER NOT NULL,
    "finished_at" INTEGER DEFAULT NULL
);

CREATE TABLE "jobs" (
    "id" INTEGER PRIMARY KEY AUTOINCREMENT,
    "queue" TEXT NOT NULL,
    "payload" TEXT NOT NULL,
    "attempts" INTEGER NOT NULL,
    "reserved_at" INTEGER DEFAULT NULL,
    "available_at" INTEGER NOT NULL,
    "created_at" INTEGER NOT NULL
);

CREATE TABLE "migrations" (
    "id" INTEGER PRIMARY KEY AUTOINCREMENT,
    "migration" TEXT NOT NULL,
    "batch" INTEGER NOT NULL
);

CREATE TABLE "password_reset_tokens" (
    "email" TEXT PRIMARY KEY,
    "token" TEXT NOT NULL,
    "created_at" TEXT DEFAULT NULL
);

CREATE TABLE "products" (
    "id" INTEGER PRIMARY KEY AUTOINCREMENT,
    "name" TEXT NOT NULL,
    "description" TEXT DEFAULT NULL,
    "image_path" TEXT DEFAULT NULL,
    "image_url" TEXT DEFAULT NULL,
    "price" NUMERIC NOT NULL,
    "cost_price" NUMERIC DEFAULT NULL,
    "stock" INTEGER NOT NULL DEFAULT 0,
    "initial_stock" INTEGER NOT NULL DEFAULT 0,
    "category_id" INTEGER NOT NULL,
    "is_active" INTEGER NOT NULL DEFAULT 1,
    "created_at" TEXT DEFAULT NULL,
    "updated_at" TEXT DEFAULT NULL,
    FOREIGN KEY ("category_id") REFERENCES "categories" ("id") ON DELETE CASCADE
);

CREATE TABLE "quotations" (
    "id" INTEGER PRIMARY KEY AUTOINCREMENT,
    "created_by" INTEGER DEFAULT NULL,
    "sale_id" INTEGER DEFAULT NULL,
    "quotation_name" TEXT DEFAULT NULL,
    "customer_name" TEXT DEFAULT NULL,
    "customer_contact" TEXT DEFAULT NULL,
    "notes" TEXT DEFAULT NULL,
    "subtotal" NUMERIC NOT NULL DEFAULT 0.00,
    "labor_fee" NUMERIC NOT NULL DEFAULT 0.00,
    "discount_type" TEXT NOT NULL DEFAULT 'amount',
    "discount" NUMERIC NOT NULL DEFAULT 0.00,
    "discount_amount" NUMERIC NOT NULL DEFAULT 0.00,
    "grand_total" NUMERIC NOT NULL DEFAULT 0.00,
    "items" TEXT NOT NULL,
    "created_at" TEXT DEFAULT NULL,
    "updated_at" TEXT DEFAULT NULL,
    FOREIGN KEY ("created_by") REFERENCES "users" ("id") ON DELETE SET NULL,
    FOREIGN KEY ("sale_id") REFERENCES "sales" ("id") ON DELETE SET NULL
);

CREATE TABLE "replacement_warranty_items" (
    "id" INTEGER PRIMARY KEY AUTOINCREMENT,
    "processed_by" INTEGER DEFAULT NULL,
    "product_id" INTEGER DEFAULT NULL,
    "expense_id" INTEGER DEFAULT NULL,
    "product_name" TEXT NOT NULL,
    "type" TEXT NOT NULL,
    "quantity" INTEGER NOT NULL,
    "unit_cost" NUMERIC NOT NULL,
    "total_cost" NUMERIC NOT NULL,
    "processed_at" TEXT NOT NULL,
    "notes" TEXT DEFAULT NULL,
    "created_at" TEXT DEFAULT NULL,
    "updated_at" TEXT DEFAULT NULL,
    FOREIGN KEY ("expense_id") REFERENCES "expenses" ("id") ON DELETE SET NULL,
    FOREIGN KEY ("processed_by") REFERENCES "users" ("id") ON DELETE SET NULL,
    FOREIGN KEY ("product_id") REFERENCES "products" ("id") ON DELETE SET NULL
);

CREATE TABLE "sale_items" (
    "id" INTEGER PRIMARY KEY AUTOINCREMENT,
    "sale_id" INTEGER NOT NULL,
    "product_id" INTEGER DEFAULT NULL,
    "product_name" TEXT NOT NULL,
    "unit_price" NUMERIC NOT NULL DEFAULT 0.00,
    "qty" INTEGER NOT NULL DEFAULT 1,
    "line_total" NUMERIC NOT NULL DEFAULT 0.00,
    "created_at" TEXT DEFAULT NULL,
    "updated_at" TEXT DEFAULT NULL,
    FOREIGN KEY ("product_id") REFERENCES "products" ("id") ON DELETE SET NULL,
    FOREIGN KEY ("sale_id") REFERENCES "sales" ("id") ON DELETE CASCADE
);

CREATE TABLE "sale_payments" (
    "id" INTEGER PRIMARY KEY AUTOINCREMENT,
    "sale_id" INTEGER NOT NULL,
    "recorded_by" INTEGER DEFAULT NULL,
    "amount" NUMERIC NOT NULL,
    "is_refund" INTEGER NOT NULL DEFAULT 0,
    "method" TEXT DEFAULT NULL,
    "reference" TEXT DEFAULT NULL,
    "notes" TEXT DEFAULT NULL,
    "paid_at" TEXT NOT NULL,
    "created_at" TEXT DEFAULT NULL,
    "updated_at" TEXT DEFAULT NULL,
    FOREIGN KEY ("recorded_by") REFERENCES "users" ("id") ON DELETE SET NULL,
    FOREIGN KEY ("sale_id") REFERENCES "sales" ("id") ON DELETE CASCADE
);

CREATE TABLE "sales" (
    "id" INTEGER PRIMARY KEY AUTOINCREMENT,
    "invoice_no" TEXT DEFAULT NULL,
    "created_by" INTEGER DEFAULT NULL,
    "sold_at" TEXT NOT NULL,
    "customer_name" TEXT DEFAULT NULL,
    "customer_contact" TEXT DEFAULT NULL,
    "notes" TEXT DEFAULT NULL,
    "subtotal" NUMERIC NOT NULL DEFAULT 0.00,
    "discount" NUMERIC NOT NULL DEFAULT 0.00,
    "expenses" NUMERIC NOT NULL DEFAULT 0.00,
    "grand_total" NUMERIC NOT NULL DEFAULT 0.00,
    "payment_status" TEXT NOT NULL DEFAULT 'paid',
    "amount_paid" NUMERIC NOT NULL DEFAULT 0.00,
    "payment_mode" TEXT DEFAULT NULL,
    "sale_status" TEXT NOT NULL DEFAULT 'completed',
    "cancelled_at" TEXT DEFAULT NULL,
    "refunded_at" TEXT DEFAULT NULL,
    "stock_restocked_at" TEXT DEFAULT NULL,
    "created_at" TEXT DEFAULT NULL,
    "updated_at" TEXT DEFAULT NULL,
    FOREIGN KEY ("created_by") REFERENCES "users" ("id") ON DELETE SET NULL
);

CREATE TABLE "sessions" (
    "id" TEXT PRIMARY KEY,
    "user_id" INTEGER DEFAULT NULL,
    "ip_address" TEXT DEFAULT NULL,
    "user_agent" TEXT DEFAULT NULL,
    "payload" TEXT NOT NULL,
    "last_activity" INTEGER NOT NULL
);

CREATE TABLE "users" (
    "id" INTEGER PRIMARY KEY AUTOINCREMENT,
    "name" TEXT NOT NULL,
    "email" TEXT NOT NULL,
    "email_verified_at" TEXT DEFAULT NULL,
    "password" TEXT NOT NULL,
    "remember_token" TEXT DEFAULT NULL,
    "created_at" TEXT DEFAULT NULL,
    "updated_at" TEXT DEFAULT NULL,
    "role" TEXT NOT NULL DEFAULT 'user',
    "admin_permissions" TEXT DEFAULT NULL,
    "theme_preference" TEXT NOT NULL DEFAULT 'light',
    "first_name" TEXT DEFAULT NULL,
    "last_name" TEXT DEFAULT NULL,
    "phone" TEXT DEFAULT NULL
);

CREATE TABLE "website_reviews" (
    "id" INTEGER PRIMARY KEY AUTOINCREMENT,
    "title" TEXT DEFAULT NULL,
    "content" TEXT DEFAULT NULL,
    "author_name" TEXT DEFAULT NULL,
    "rating" INTEGER NOT NULL DEFAULT 5,
    "sort_order" INTEGER NOT NULL DEFAULT 1,
    "is_active" INTEGER NOT NULL DEFAULT 1,
    "created_at" TEXT DEFAULT NULL,
    "updated_at" TEXT DEFAULT NULL
);

CREATE INDEX "audit_logs_action_index" ON "audit_logs" ("action");

CREATE INDEX "audit_logs_created_at_index" ON "audit_logs" ("created_at");

CREATE INDEX "audit_logs_target_type_target_id_index" ON "audit_logs" ("target_type", "target_id");

CREATE INDEX "audit_logs_user_id_foreign" ON "audit_logs" ("user_id");

CREATE INDEX "bundle_ads_bundle_type_is_active_sort_order_index" ON "bundle_ads" ("bundle_type", "is_active", "sort_order");

CREATE INDEX "cache_expiration_index" ON "cache" ("expiration");

CREATE INDEX "cache_locks_expiration_index" ON "cache_locks" ("expiration");

CREATE INDEX "categories_parent_id_foreign" ON "categories" ("parent_id");

CREATE INDEX "expenses_category_index" ON "expenses" ("category");

CREATE INDEX "expenses_created_by_foreign" ON "expenses" ("created_by");

CREATE INDEX "expenses_spent_at_index" ON "expenses" ("spent_at");

CREATE UNIQUE INDEX "failed_jobs_uuid_unique" ON "failed_jobs" ("uuid");

CREATE INDEX "featured_builds_is_active_sort_order_index" ON "featured_builds" ("is_active", "sort_order");

CREATE INDEX "jobs_queue_index" ON "jobs" ("queue");

CREATE INDEX "products_active_category_id_idx" ON "products" ("is_active", "category_id", "id");

CREATE INDEX "products_active_price_idx" ON "products" ("is_active", "price");

CREATE INDEX "products_active_stock_idx" ON "products" ("is_active", "stock");

CREATE INDEX "products_category_id_foreign" ON "products" ("category_id");

CREATE INDEX "quotations_created_by_foreign" ON "quotations" ("created_by");

CREATE INDEX "quotations_sale_id_foreign" ON "quotations" ("sale_id");

CREATE INDEX "replacement_warranty_items_expense_id_foreign" ON "replacement_warranty_items" ("expense_id");

CREATE INDEX "replacement_warranty_items_processed_by_foreign" ON "replacement_warranty_items" ("processed_by");

CREATE INDEX "replacement_warranty_items_product_id_foreign" ON "replacement_warranty_items" ("product_id");

CREATE INDEX "replacement_warranty_processed_at_index" ON "replacement_warranty_items" ("processed_at");

CREATE INDEX "replacement_warranty_product_name_index" ON "replacement_warranty_items" ("product_name");

CREATE INDEX "replacement_warranty_type_index" ON "replacement_warranty_items" ("type");

CREATE INDEX "sale_items_product_id_foreign" ON "sale_items" ("product_id");

CREATE INDEX "sale_items_sale_id_foreign" ON "sale_items" ("sale_id");

CREATE INDEX "sale_payments_recorded_by_foreign" ON "sale_payments" ("recorded_by");

CREATE INDEX "sale_payments_sale_paid_at_index" ON "sale_payments" ("sale_id", "paid_at");

CREATE INDEX "sale_payments_sale_refund_index" ON "sale_payments" ("sale_id", "is_refund");

CREATE INDEX "sales_created_by_foreign" ON "sales" ("created_by");

CREATE INDEX "sales_customer_name_index" ON "sales" ("customer_name");

CREATE UNIQUE INDEX "sales_invoice_no_unique" ON "sales" ("invoice_no");

CREATE INDEX "sales_lifecycle_index" ON "sales" ("cancelled_at", "refunded_at");

CREATE INDEX "sales_payment_status_index" ON "sales" ("payment_status");

CREATE INDEX "sales_sale_status_index" ON "sales" ("sale_status");

CREATE INDEX "sales_sold_at_index" ON "sales" ("sold_at");

CREATE INDEX "sales_sold_payment_index" ON "sales" ("sold_at", "payment_status");

CREATE INDEX "sessions_last_activity_index" ON "sessions" ("last_activity");

CREATE INDEX "sessions_user_id_index" ON "sessions" ("user_id");

CREATE UNIQUE INDEX "users_email_unique" ON "users" ("email");

CREATE INDEX "users_role_index" ON "users" ("role");

CREATE INDEX "website_reviews_is_active_sort_order_index" ON "website_reviews" ("is_active", "sort_order");

COMMIT;
PRAGMA foreign_keys = ON;
